class Solution:
    def runningSum(self, nums):
        return [sum(nums[:i + 1]) for i in range(len(nums))]

solutions.python:
class Solution:
    def runningSum(self, nums):
        res = []
        total = 0
        for x in nums:
            total += x
            res.append(total)
        return res

